INSERT INTO `v1_40c6e39df9368930b696e842187953763e7f4afff2c80f8c78dc8d1dbcdc687d` VALUES (1010801, 1010801033, 0, "けっ。\nな～にが若女将ですか……\n根性のねじ曲がったババ女将のくせに。", 1, 0.2, 1, 10, 2, 11, 0);
