INSERT INTO `v1_40c6e39df9368930b696e842187953763e7f4afff2c80f8c78dc8d1dbcdc687d` VALUES (1010801, 1010801048, 0, "人聞きが悪いな～\n危険なものなんて入ってないよ～\n……むしろイノリちゃんだって\nよく知ってるものだし？", 1, 0.2, 1, 10, 1, 11, 0);
INSERT INTO `v1_40c6e39df9368930b696e842187953763e7f4afff2c80f8c78dc8d1dbcdc687d` VALUES (1010801, 1010801049, "", "", "", "", "", "", 0, 91, "");
