INSERT INTO `v1_40c6e39df9368930b696e842187953763e7f4afff2c80f8c78dc8d1dbcdc687d` VALUES (1010801, 1010801053, 0, "言われてみれば……クンクン。\nこのお湯の匂い\nどっかで嗅いだような気がするです。", 1, 0.2, 1, 10, 2, 11, 0);
INSERT INTO `v1_40c6e39df9368930b696e842187953763e7f4afff2c80f8c78dc8d1dbcdc687d` VALUES (1010801, 1010801054, "", "", "", "", "", "", 0, 91, "");
