INSERT INTO `v1_40c6e39df9368930b696e842187953763e7f4afff2c80f8c78dc8d1dbcdc687d` VALUES (1010801, 1010801072, 0, "それにしても……\nふぅ。\n実の量を多くしすぎたかな～？\nちょっと火照ってきちゃった～", 1, 0.2, 1, 10, 1, 11, 0);
