INSERT INTO `v1_40c6e39df9368930b696e842187953763e7f4afff2c80f8c78dc8d1dbcdc687d` VALUES (1010806, 1010806029, 0, "入浴時間には気をつけてね？\n脂肪燃焼効果が高いから……\n入りすぎると大変なことになるわよ。", 1, 0.2, 1, 10, 1, 11, 0);
INSERT INTO `v1_40c6e39df9368930b696e842187953763e7f4afff2c80f8c78dc8d1dbcdc687d` VALUES (1010806, 1010806030, "", "", "", "", "", "", 0, 91, "");
