INSERT INTO `v1_40c6e39df9368930b696e842187953763e7f4afff2c80f8c78dc8d1dbcdc687d` VALUES (1010806, 1010806034, 0, "ええ、ええ！　もちろんですわ！\nそれにしても……短時間で\nこれほどの温泉が用意できるとは。\nさすがは『隻眼の悪魔』ですわね？", 1, 0.2, 1, 10, 2, 11, 0);
INSERT INTO `v1_40c6e39df9368930b696e842187953763e7f4afff2c80f8c78dc8d1dbcdc687d` VALUES (1010806, 1010806035, "", "", "", "", "", "", 0, 91, "");
