INSERT INTO `v1_40c6e39df9368930b696e842187953763e7f4afff2c80f8c78dc8d1dbcdc687d` VALUES (1010806, 1010806039, 0, "お褒めの言葉どうも。\nといっても……\n私はあなたの依頼に応えただけだけど。", 1, 0.2, 1, 10, 1, 11, 0);
