INSERT INTO `v1_40c6e39df9368930b696e842187953763e7f4afff2c80f8c78dc8d1dbcdc687d` VALUES (1010806, 1010806058, 0, "この汗の量……\nおかしくありませんこと？\nいくら発汗作用が優れているからと\nいっても、これは……", 1, 0.2, 1, 10, 2, 11, 0);
