INSERT INTO `v1_40c6e39df9368930b696e842187953763e7f4afff2c80f8c78dc8d1dbcdc687d` VALUES (1010806, 1010806068, 0, "……ねえ、クレジッタ。\nあなた、秘書さんに出張だってウソを\nついてここに来たのよね？", 1, 0.2, 1, 10, 1, 11, 0);
